import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_STYLE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Tests for indentation issues with try/catch and typealias
 */
class IndentationRuleIssueTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a try-catch with expression-style function should not extra indent catch block`() {
        val code =
            """
            fun test() = try {
            1
            }
            catch(_: Throwable) {
            2
            }
            """.trimIndent()
        val formattedCode =
            """
            fun test() = try {
                1
            }
            catch(_: Throwable) {
                2
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasLintViolations(
                LintViolation(2, 1, "Unexpected indentation (0) (should be 2)"),
                LintViolation(4, 1, "Unexpected indentation (0) (should be 2)"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a try-catch-finally with expression-style function should not extra indent catch and finally blocks`() {
        val code =
            """
            fun test() = try {
            1
            } catch(_: Throwable) {
            2
            } finally {
            3
            }
            """.trimIndent()
        val formattedCode =
            """
            fun test() = try {
                1
            } catch(_: Throwable) {
                2
            } finally {
                3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasLintViolations(
                LintViolation(2, 1, "Unexpected indentation (0) (should be 2)"),
                LintViolation(3, 1, "Unexpected indentation (0) (should be 2)"),
                LintViolation(5, 1, "Unexpected indentation (0) (should be 2)"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a typealias with multiline type should indent the type`() {
        val code =
            """
            typealias Foo =
            HashMap<Bar, Baz?>
            """.trimIndent()
        val formattedCode =
            """
            typealias Foo =
                HashMap<Bar, Baz?>
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolation(2, 1, "Unexpected indentation (0) (should be 4)")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a typealias with multiline type with 2 space indent should indent the type correctly`() {
        val code =
            """
            typealias Foo =
            HashMap<Bar, Baz?>
            """.trimIndent()
        val formattedCode =
            """
            typealias Foo =
              HashMap<Bar, Baz?>
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasLintViolation(2, 1, "Unexpected indentation (0) (should be 2)")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a nested try-catch with expression-style function should not extra indent catch block`() {
        val code =
            """
            fun test() {
            val x = try {
            1
            }
            catch(_: Throwable) {
            2
            }
            }
            """.trimIndent()
        val formattedCode =
            """
            fun test() {
                val x = try {
                    1
                }
                catch(_: Throwable) {
                    2
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 1, "Unexpected indentation (0) (should be 4)"),
                LintViolation(3, 1, "Unexpected indentation (0) (should be 8)"),
                LintViolation(5, 1, "Unexpected indentation (0) (should be 4)"),
                LintViolation(6, 1, "Unexpected indentation (0) (should be 8)"),
            ).isFormattedAs(formattedCode)
    }
}
